 1	import * as React from 'react';
 2	import { Card, CardBody } from '@patternfly/react-core';
 3	
 4	import { RichSpanData } from 'types/TracingInfo';
 5	import { TracingUrlProvider } from 'types/Tracing';
 6	import { SpanTable } from './SpanTable';
 7	import { FilterSelected, StatefulFilters } from 'components/Filters/StatefulFilters';
 8	import { spanFilters } from './Filters';
 9	import { runFilters } from 'components/FilterList/FilterHelper';
10	import { ActiveFiltersInfo } from 'types/Filters';
11	import { TraceLabels } from './TraceLabels';
12	
13	interface SpanDetailsProps {
14	  cluster?: string;
15	  externalURLProvider?: TracingUrlProvider;
16	  fromWaypoint: boolean;
17	  items: RichSpanData[];
18	  namespace: string;
19	  target: string;
20	  traceID: string;
21	  waypointServiceFilter?: string; // This is used to match the span (operationName) as this is different than the workload
22	}
23	
24	export const SpanDetails: React.FC<SpanDetailsProps> = (props: SpanDetailsProps) => {
25	  const filters = spanFilters(props.items);
26	
27	  const [activeFilters, setActiveFilters] = React.useState<ActiveFiltersInfo>(FilterSelected.init(filters));
28	  const filteredItems = runFilters(props.items, filters, activeFilters);
29	
30	  return (
31	    <Card isCompact>
32	      <CardBody>
33	        <StatefulFilters initialFilters={filters} onFilterChange={active => setActiveFilters(active)}>
34	          <TraceLabels
35	            spans={props.items}
36	            filteredSpans={activeFilters.filters.length > 0 ? filteredItems : undefined}
37	            oneline={true}
38	          />
39	        </StatefulFilters>
40	
41	        {props.traceID && (
42	          <SpanTable
43	            items={filteredItems}
44	            namespace={props.namespace}
45	            externalURLProvider={props.externalURLProvider}
46	            cluster={props.cluster}
47	            target={props.waypointServiceFilter ? props.waypointServiceFilter : props.target}
48	            traceID={props.traceID}
49	            fromWaypoint={props.fromWaypoint}
50	          />
51	        )}
52	      </CardBody>
53	    </Card>
54	  );
55	};

